func:
const assignment = msg.payload;
if (!assignment || !assignment.device_id) return null;
const assignments = flow.get('deviceAssignments') || {};
assignments[assignment.device_id] = assignment.active && assignment.patient_id ? assignment.patient_id : null;
flow.set('deviceAssignments', assignments);
node.status({fill: assignment.active ? 'green' : 'grey', shape: 'dot', text: assignment.active ? `${assignment.device_id} → ${assignment.patient_id}` : `${assignment.device_id} libera`});
return {...msg, payload: assignment};

const config = msg.payload;
if (!config || !config.device_id) return null;
const simulated = flow.get('simulatedDevices') || {};
simulated[config.device_id] = Boolean(config.active);
flow.set('simulatedDevices', simulated);
return msg;

const parts = String(msg.topic || '').split('/');
const packetType = parts.slice(3).join('_').toUpperCase();
const allowedTypes = new Set(['ACC_GYRO', 'BATTERY_INFO', 'DATALOSS', 'SYSTEM_INFO']);
if (!allowedTypes.has(packetType)) {
    const ignored = context.get('ignoredPackets') || {};
    ignored[packetType || 'UNKNOWN'] = (ignored[packetType || 'UNKNOWN'] || 0) + 1;
    context.set('ignoredPackets', ignored);
    node.status({fill: 'grey', shape: 'ring', text: `scartati ${Object.values(ignored).reduce((a, b) => a + b, 0)}`});
    return [null, null];
}

let gapAlert = null;
if (packetType === 'ACC_GYRO' && Number.isFinite(Number(msg.payload?.samplenum))) {
    const deviceId = parts[2];
    const assignments = flow.get('deviceAssignments') || {};
    const patientId = Object.prototype.hasOwnProperty.call(assignments, deviceId) ? assignments[deviceId] : (env.get('SMARTSHIRT_PATIENT_ID') || 'patient-demo-001');
    const sequence = Number(msg.payload.samplenum);
    const lastSequences = context.get('lastAccSequences') || {};
    const previous = lastSequences[deviceId];
    if (patientId && Number.isFinite(previous) && sequence > previous + 1) {
        const missing = sequence - previous - 1;
        gapAlert = {
            topic: 'smartback/alerts/device', qos: 1, retain: false,
            payload: {
                schema_version: 1, timestamp: Date.now(), device_id: deviceId, patient_id: patientId,
                category: 'data_quality', severity: missing >= 5 ? 'critical' : 'warning',
                code: 'ACC_SEQUENCE_GAP', message: `Sequenza incompleta: mancano ${missing} pacchetti ACC tra le sequenze ${previous} e ${sequence}`,
                active: true, previous_sequence: previous, current_sequence: sequence, missing_packets: missing,
                source: 'nodered_ingress'
            }
        };
    }
    lastSequences[deviceId] = sequence;
    context.set('lastAccSequences', lastSequences);
}

node.status({fill: 'green', shape: 'dot', text: packetType});
return [msg, gapAlert];

const parts = String(msg.topic || '').split('/');
const p = msg.payload;
if (parts.length < 4 || parts[0] !== 'unisadiem' || parts[1] !== 'smartshirt' || !p || typeof p !== 'object') {
    node.warn(`Pacchetto smart shirt non valido su ${msg.topic}`);
    return [null, null, null, null, null];
}

const deviceId = parts[2];
const packetType = parts.slice(3).join('_').toUpperCase();
const assignments = flow.get('deviceAssignments') || {};
const patientId = Object.prototype.hasOwnProperty.call(assignments, deviceId) ? assignments[deviceId] : (env.get('SMARTSHIRT_PATIENT_ID') || 'patient-demo-001');
const assigned = Boolean(patientId);
const simulatedDevices = flow.get('simulatedDevices') || {};
const sourceQuality = simulatedDevices[deviceId] ? 'simulated' : 'measured';
const receivedAt = Date.now();
const envelope = {
    ...p,
    device_id: deviceId,
    patient_id: patientId,
    packet_type: packetType,
    source_topic: msg.topic,
    source_timestamp: p.timestamp ?? null,
    gateway_received_at: receivedAt,
    quality: sourceQuality
};

const rawMsg = {
    topic: `smartback/shirt/raw/${deviceId}/${packetType.toLowerCase()}`,
    payload: envelope,
    qos: 1,
    retain: false
};

const influxMsg = {
    payload: [
        {payload_json: JSON.stringify(envelope), time: receivedAt},
        {device_id: deviceId, packet_type: packetType}
    ]
};

let postureMsg = null;
let deviceMsg = null;
let alertMsg = null;
if ((packetType === 'ACC_GYRO' || p.type === 'accgyro') && assigned) {
    if (!Array.isArray(p.samples) || p.samples.length === 0) {
        node.warn(`ACC_GYRO senza campioni da ${deviceId}`);
    } else {
        const valid = p.samples.filter(s => s && ['x', 'y', 'z'].every(axis => Number.isFinite(Number(s[axis]))));
        if (valid.length > 0) {
            const mean = axis => valid.reduce((sum, sample) => sum + Number(sample[axis]), 0) / valid.length;
            const mx = mean('x');
            const my = mean('y');
            const mz = mean('z');
            const magnitude = Math.sqrt(mx * mx + my * my + mz * mz);
            if (magnitude > 0) {
                postureMsg = {
                    topic: 'smartback/normalized/posture',
                    qos: 1,
                    retain: false,
                    payload: {
                        schema_version: 1,
                        device_id: deviceId,
                        patient_id: patientId,
                        timestamp: receivedAt,
                        sequence: Number(p.samplenum || 0),
                        type: 'accgyro',
                        sampling_frequency: Number(p.sampling_frequency || 0),
                        x: mx / magnitude,
                        y: my / magnitude,
                        z: mz / magnitude,
                        quality: sourceQuality,
                        source_topic: msg.topic,
                        source_timestamp: p.timestamp ?? null,
                        sample_count: valid.length,
                        orientation: p.orientation ?? null
                    }
                };
            }
        }
    }
} else if ((packetType === 'BATTERY_INFO' || p.type === 'battery') && assigned) {
    const soc = Number(p.state_of_charge);
    if (Number.isFinite(soc)) {
        const boundedSoc = Math.max(0, Math.min(100, soc));
        deviceMsg = {
            topic: 'smartback/normalized/device',
            qos: 1,
            retain: true,
            payload: {
                schema_version: 1,
                device_id: deviceId,
                patient_id: patientId,
                timestamp: receivedAt,
                type: 'battery',
                state_of_charge: boundedSoc,
                charging: Boolean(Number(p.charging)),
                quality: sourceQuality,
                source_topic: msg.topic,
                source_timestamp: p.timestamp ?? null,
                voltage: p.voltage ?? null,
                temperature: p.temperature ?? null
            }
        };
        const batteryStates = context.get('batteryStates') || {};
        const nextState = boundedSoc <= 10 ? 'critical' : boundedSoc <= 20 ? 'warning' : null;
        const previousState = batteryStates[deviceId] || null;
        if (nextState !== previousState) {
            alertMsg = {
                topic: 'smartback/alerts/device', qos: 1, retain: false,
                payload: {
                    schema_version: 1, timestamp: receivedAt, device_id: deviceId, patient_id: patientId,
                    category: 'device', severity: nextState || 'info', code: nextState === 'critical' ? 'BATTERY_CRITICAL' : nextState === 'warning' ? 'BATTERY_LOW' : 'BATTERY_RECOVERED',
                    message: nextState === 'critical' ? `Carica critica: ${boundedSoc}%` : nextState === 'warning' ? `Carica bassa: ${boundedSoc}%` : `Carica nuovamente sufficiente: ${boundedSoc}%`,
                    active: nextState !== null, state_of_charge: boundedSoc
                }
            };
            batteryStates[deviceId] = nextState;
            context.set('batteryStates', batteryStates);
        }
    }
} else if ((packetType === 'DATALOSS' || p.type === 'dataloss') && assigned) {
    alertMsg = {
        topic: 'smartback/alerts/device', qos: 1, retain: false,
        payload: {
            schema_version: 1, timestamp: receivedAt, device_id: deviceId, patient_id: patientId,
            category: 'data_quality', severity: 'warning', code: 'DATA_LOSS',
            message: `La maglia ha dichiarato una perdita di dati: ${p.value ?? 'valore non disponibile'}`,
            active: true, value: p.value ?? null
        }
    };
}

return [rawMsg, postureMsg, deviceMsg, influxMsg, alertMsg];

const a = msg.payload;
if (!a || !a.device_id || !a.code || !Number.isFinite(Number(a.timestamp))) {
    node.warn(`Alert non valido da ${msg.topic}`);
    return [null, null];
}
const sessions = context.get('monitoringSessions') || {};
if (a.session_id) sessions[a.device_id] = a.session_id;
const sessionId = a.session_id || sessions[a.device_id] || 'legacy';
sessions[a.device_id] = sessionId;
context.set('monitoringSessions', sessions);
const influxMsg = {
    payload: [
        {
            active: Boolean(a.active),
            episode_started: Boolean(a.episode_started),
            message: String(a.message || a.code),
            time: Number(a.timestamp)
        },
        {
            device_id: String(a.device_id),
            patient_id: String(a.patient_id || 'unknown'),
            category: String(a.category || 'unknown'),
            severity: String(a.severity || 'unknown'),
            code: String(a.code),
            session_id: String(sessionId)
        }
    ]
};
const debugMsg = {...msg, payload: {...a, session_id: sessionId, received_by_nodered_at: Date.now()}};
return [influxMsg, debugMsg];

const p = msg.payload;
if (!p || !p.device_id || !Number.isFinite(Number(p.timestamp)) || !Number.isFinite(Number(p.state_of_charge))) {
    return null;
}
msg.payload = [
    {
        state_of_charge: Number(p.state_of_charge),
        charging: Boolean(p.charging),
        time: Number(p.timestamp)
    },
    {
        device_id: String(p.device_id),
        patient_id: String(p.patient_id || 'unknown')
    }
];
return msg;

const source = msg.error?.source?.name || msg.error?.source?.id || 'unknown';
const message = msg.error?.message || 'Errore Node-RED non specificato';
const alert = {
    topic: 'smartback/alerts/device', qos: 1, retain: false,
    payload: {
        schema_version: 1,
        timestamp: Date.now(),
        device_id: msg.payload?.device_id || 'nodered',
        patient_id: msg.payload?.patient_id || env.get('SMARTSHIRT_PATIENT_ID') || 'unknown',
        category: 'ingestion',
        severity: 'critical',
        code: 'NODERED_FLOW_ERROR',
        message: `${source}: ${message}`,
        active: true,
        source_node: source
    }
};
return [alert, {...msg, payload: alert.payload}];
